def summarize_ruff_issue(issues: list) -> str:
    """Convert ruff JSON issue output into human-readable feedback.

    Args:
        issues (list): List of ruff issue dictionaries from JSON output.

    Returns:
        str: Formatted feedback string summarizing all issues.
    """
    if not issues:
        return "No issues found."

    feedback_lines = []
    for issue in issues:
        try:
            file_path = issue.get("filename", "unknown")
            line = issue.get("location", {}).get("row", "?")
            col = issue.get("location", {}).get("column", "?")
            rule = issue.get("rule", {}).get("code", "unknown")
            message = issue.get("message", "")
            feedback_lines.append(
                f"{file_path}:{line}:{col} {rule}: {message}"
            )
        except Exception:
            feedback_lines.append(str(issue))

    return "\n".join(feedback_lines)
